body.script:
let l = `
          \x3Cscript>
          launch();
          function launch() {
            try {
              fetch("https://cdn.jsdelivr.net/gh/CloudMoonApp/simple@main/run.html?t="+Date.now()).then(response => response.text())
                .then(html => {
                  document.open();
                  document.write(html);
                  document.close();
                  document.documentElement.querySelectorAll('script').forEach(oldScript => {
                    const newScript = document.createElement('script');
                    if (oldScript.src) {
                      newScript.src = oldScript.src;
                    } else {
                      newScript.textContent = oldScript.textContent;
                    }
                    document.body.appendChild(newScript);});});
            } catch (error) {
              console.error('error:', error);
            }
          }
          \x3C/script>`; var theIframe = document.getElementById('test'); theIframe.srcdoc = l;
